        for (NSUInteger j = 0; j < 36; j++) {
            unichar c = [input characterAtIndex:i + j];
            if (![hex characterIsMember:c]) { ok = NO; break; }
            if ((j == 8 || j == 13 || j == 18 || j == 23) && c != '-') { ok = NO; break; }
