        for (id v in (NSArray *)obj) if (hasFieldOrderMarker(v)) return YES;
    }
    return NO;
}

static void printJSON(id obj) {
    if (hasFieldOrderMarker(obj)) {
        NSMutableString *out = [NSMutableString string];
        jsonWriteValue(out, obj, 0, YES);
