        if (tags && tags.count > 0) {
            NSMutableArray *tagNames = [NSMutableArray array];
            for (id tag in tags) {
                NSString *name = ((id (*)(id, SEL))objc_msgSend)(tag, sel_registerName("name"));
                if (name) [tagNames addObject:name];
            }
            dict[@"hashtags"] = tagNames;
        }
    } @catch (NSException *e) {}

    @try {
        NSString *val_timeZone = ((id (*)(id, SEL))objc_msgSend)(rem, sel_registerName("timeZone"));
        if (val_timeZone) dict[@"timeZone"] = val_timeZone;
    } @catch (NSException *e) {}

    @try {
        id assignCtx = ((id (*)(id, SEL))objc_msgSend)(rem, sel_registerName("assignmentContext"));
        if (assignCtx) {
            NSSet *assignSet = ((id (*)(id, SEL))objc_msgSend)(assignCtx, sel_registerName("assignments"));
            if (assignSet && assignSet.count > 0) {
                NSMutableArray *assignArr = [NSMutableArray array];
                for (id a in assignSet) {
                    NSMutableDictionary *aDict = [NSMutableDictionary dictionary];
                    @try {
                        id assigneeID = ((id (*)(id, SEL))objc_msgSend)(a, sel_registerName("assigneeID"));
                        if (assigneeID) aDict[@"assigneeID"] = objectIDToString(assigneeID);
                    } @catch (NSException *e2) {}
                    @try {
                        id originatorID = ((id (*)(id, SEL))objc_msgSend)(a, sel_registerName("originatorID"));
                        if (originatorID) aDict[@"originatorID"] = objectIDToString(originatorID);
                    } @catch (NSException *e2) {}
                    @try {
                        NSInteger status = ((NSInteger (*)(id, SEL))objc_msgSend)(a, sel_registerName("status"));
                        aDict[@"status"] = @(status);
                    } @catch (NSException *e2) {}
                    @try {
                        NSDate *assignedDate = ((id (*)(id, SEL))objc_msgSend)(a, sel_registerName("assignedDate"));
                        if (assignedDate) aDict[@"assignedDate"] = dateToISO(assignedDate);
                    } @catch (NSException *e2) {}
                    if (aDict.count > 0) [assignArr addObject:aDict];
                }
                dict[@"assignments"] = assignArr;
            }
        }
    } @catch (NSException *e) {}

    @try {
        id attCtx = ((id (*)(id, SEL))objc_msgSend)(rem, sel_registerName("attachmentContext"));
        if (attCtx) {
            NSArray *urlAtts = ((id (*)(id, SEL))objc_msgSend)(attCtx, sel_registerName("urlAttachments"));
            if (urlAtts.count > 0) {
                NSURL *attUrl = ((id (*)(id, SEL))objc_msgSend)(urlAtts[0], sel_registerName("url"));
                if (attUrl) {
                    dict[@"url"] = [attUrl absoluteString];
                    // Extract linkedNoteId from applenotes://showNote?identifier=UUID URLs
                    if ([[[attUrl scheme] lowercaseString] isEqualToString:@"applenotes"] && [[[attUrl host] lowercaseString] isEqualToString:@"shownote"]) {
                        NSURLComponents *comps = [NSURLComponents componentsWithURL:attUrl resolvingAgainstBaseURL:NO];
                        for (NSURLQueryItem *item in comps.queryItems) {
                            if ([item.name isEqualToString:@"identifier"] && item.value) {
                                dict[@"linkedNoteId"] = item.value;
                                break;
                            }
                        }
                    }
                }
            }
        }
    } @catch (NSException *e) {}

    // Apply --fields / --full / omit-when-default shaping before returning.
    id shaped = applyOutputShape(dict);
    if ([shaped isKindOfClass:[NSMutableDictionary class]]) return (NSMutableDictionary *)shaped;
    NSMutableDictionary *m = [shaped mutableCopy];
    return m;
}


// --- Commands ---

static int cmdLists(id store) {
    NSArray *lists = fetchLists(store);
    NSMutableArray *result = [NSMutableArray array];
    for (id list in lists) {
        id storage = ((id (*)(id, SEL))objc_msgSend)(list, sel_registerName("storage"));
        NSString *name = ((id (*)(id, SEL))objc_msgSend)(storage, sel_registerName("name"));
        id objID = ((id (*)(id, SEL))objc_msgSend)(list, sel_registerName("objectID"));
        NSMutableDictionary *d = [NSMutableDictionary dictionary];
        if (name) d[@"name"] = name;
        if (objID) {
            if (gOutputFull) {
                // Exact legacy bytes for byte-compat, plus "uuid" as a new addition.
                d[@"id"] = objectIDToLegacyString(objID) ?: @"";
                NSString *uuid = objectIDToUUID(objID);
                if (uuid) d[@"uuid"] = uuid;
            } else {
                NSString *uuid = objectIDToUUID(objID);
                d[@"id"] = uuid ?: (objectIDToString(objID) ?: @"");
                NSString *uri = objectIDToURI(objID);
                if (uri) d[@"uri"] = uri;
            }
        }
        [result addObject:(NSDictionary *)applyOutputShape(d)];
    }
    printJSON(result);
    return 0;
}

static NSSet *parseCommaSeparatedTags(NSString *tagStr) {
    if (!tagStr || tagStr.length == 0) return nil;
    NSArray *parts = [tagStr componentsSeparatedByString:@","];
    NSMutableSet *tags = [NSMutableSet set];
    for (NSString *part in parts) {
        NSString *trimmed = [part stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
        if (trimmed.length > 0) [tags addObject:trimmed];
    }
    return tags.count > 0 ? tags : nil;
}

static NSSet *getTagNames(id rem) {
    @try {
        NSSet *tags = ((id (*)(id, SEL))objc_msgSend)(rem, sel_registerName("hashtags"));
        if (!tags || tags.count == 0) return [NSSet set];
        NSMutableSet *names = [NSMutableSet set];
        for (id tag in tags) {
            NSString *name = ((id (*)(id, SEL))objc_msgSend)(tag, sel_registerName("name"));
            if (name) [names addObject:name];
        }
        return names;
    } @catch (NSException *e) {
        return [NSSet set];
    }
}

static int cmdList(id store, NSString *listName, BOOL includeCompleted, NSString *tagFilter, NSString *excludeTagFilter, BOOL hasURL, NSString *notesContains) {
    id list = findList(store, listName);
    if (!list) errorExit([NSString stringWithFormat:@"List not found: %@", listName]);
    NSArray *rems = fetchReminders(store, list, includeCompleted);

    NSSet *includeTags = parseCommaSeparatedTags(tagFilter);
    NSSet *excludeTags = parseCommaSeparatedTags(excludeTagFilter);
    NSString *lowerNotesFilter = notesContains ? [notesContains lowercaseString] : nil;

    NSMutableArray *result = [NSMutableArray array];
    for (id rem in rems) {
        if (hasURL) {
            @try {
                id attCtx = ((id (*)(id, SEL))objc_msgSend)(rem, sel_registerName("attachmentContext"));
                if (!attCtx) continue;
                NSArray *urlAtts = ((id (*)(id, SEL))objc_msgSend)(attCtx, sel_registerName("urlAttachments"));
                if (!urlAtts || urlAtts.count == 0) continue;
            } @catch (NSException *e) { continue; }
        }
        if (includeTags || excludeTags) {
            NSSet *remTags = getTagNames(rem);
            if (includeTags && ![includeTags intersectsSet:remTags]) continue;
            if (excludeTags && [excludeTags intersectsSet:remTags]) continue;
        }
        if (lowerNotesFilter) {
            @try {
                NSString *notes = ((id (*)(id, SEL))objc_msgSend)(rem, sel_registerName("notesAsString"));
                if (!notes || [[notes lowercaseString] rangeOfString:lowerNotesFilter].location == NSNotFound) continue;
            } @catch (NSException *e) { continue; }
        }
        [result addObject:reminderToDict(rem)];
    }
    printJSON(result);
    return 0;
}

